productos:
/* ==========================================
   PRODUCTOS.CSS - Product Management
   ========================================== */

:root {
  --color-primary: #1e40af;
  --color-secondary: #0f172a;
  --color-success: #10b981;
  --color-warning: #f59e0b;
  --color-danger: #ef4444;
  --color-light: #f3f4f6;
  --color-border: #e5e7eb;
  --color-text: #1f2937;
  --color-text-light: #6b7280;
  --color-white: #ffffff;
  --spacing-xs: 0.25rem;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 1.5rem;
  --spacing-xl: 2rem;
  --spacing-2xl: 3rem;
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
  --transition: all 0.3s ease;
}

.productos-container {
  width: 100%;
  padding: var(--spacing-xl);
  background: linear-gradient(135deg, #f3f4f6 0%, #ffffff 100%);
  min-height: 100vh;
}

.productos-header {
  margin-bottom: var(--spacing-2xl);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-lg);
}

.productos-title {
  font-size: 2rem;
  font-weight: 700;
  color: var(--color-secondary);
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin: 0;
}

.productos-actions {
  display: flex;
  gap: var(--spacing-md);
  align-items: center;
}

.btn-crear-producto {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  color: var(--color-white);
  border: none;
  padding: var(--spacing-md) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  box-shadow: var(--shadow-md);
}

.btn-crear-producto:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 20px -4px rgba(30, 64, 175, 0.3);
}

.btn-crear-producto:active {
  transform: translateY(0);
}

.productos-filters {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  margin-bottom: var(--spacing-xl);
  border: 1px solid var(--color-border);
  box-shadow: var(--shadow-sm);
}

.filter-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: var(--spacing-lg);
}

.filter-group {
  display: flex;
  flex-direction: column;
}

.filter-label {
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--color-text);
  margin-bottom: var(--spacing-sm);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.filter-input,
.filter-select {
  padding: var(--spacing-md) var(--spacing-md);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 0.95rem;
  transition: var(--transition);
  background: var(--color-white);
  color: var(--color-text);
  font-family: inherit;
}

.filter-input:focus,
.filter-select:focus {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px rgba(30, 64, 175, 0.1);
  background: linear-gradient(to bottom, var(--color-white), #fafbfc);
}

.filter-buttons {
  display: flex;
  gap: var(--spacing-md);
  grid-column: 1 / -1;
  justify-content: flex-end;
}

.btn-filter {
  padding: var(--spacing-md) var(--spacing-lg);
  border: none;
  border-radius: var(--radius-md);
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  font-size: 0.95rem;
}

.btn-filter-apply {
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  color: var(--color-white);
  box-shadow: var(--shadow-md);
}

.btn-filter-apply:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 20px -4px rgba(30, 64, 175, 0.3);
}

.btn-filter-reset {
  background: var(--color-light);
  color: var(--color-text);
  border: 1px solid var(--color-border);
}

.btn-filter-reset:hover {
  background: #e5e7eb;
  border-color: #d1d5db;
}

.productos-table-container {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--color-border);
}

.productos-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.95rem;
}

.productos-thead {
  background: linear-gradient(to right, #f9fafb, #f3f4f6);
  border-bottom: 2px solid var(--color-border);
}

.productos-th {
  padding: var(--spacing-lg);
  text-align: left;
  font-weight: 700;
  color: var(--color-secondary);
  text-transform: uppercase;
  font-size: 0.875rem;
  letter-spacing: 0.5px;
  white-space: nowrap;
}

.productos-tbody tr {
  border-bottom: 1px solid var(--color-border);
  transition: var(--transition);
}

.productos-tbody tr:hover {
  background: linear-gradient(to right, #f9fafb, #f3f4f6);
}

.productos-td {
  padding: var(--spacing-lg);
  color: var(--color-text);
  vertical-align: middle;
}

.product-name {
  font-weight: 600;
  color: var(--color-primary);
}

.product-code {
  font-family: 'Courier New', monospace;
  background: var(--color-light);
  padding: var(--spacing-xs) var(--spacing-sm);
  border-radius: var(--radius-sm);
  color: var(--color-secondary);
  font-size: 0.85rem;
}

.product-price {
  font-weight: 700;
  color: var(--color-success);
  font-size: 1.05rem;
}

.status-badge {
  display: inline-block;
  padding: var(--spacing-xs) var(--spacing-md);
  border-radius: var(--radius-sm);
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  width: fit-content;
}

.status-active {
  background: rgba(16, 185, 129, 0.1);
  color: var(--color-success);
  border-left: 3px solid var(--color-success);
}

.status-inactive {
  background: rgba(107, 114, 128, 0.1);
  color: var(--color-text-light);
  border-left: 3px solid var(--color-text-light);
}

.status-warning {
  background: rgba(245, 158, 11, 0.1);
  color: var(--color-warning);
  border-left: 3px solid var(--color-warning);
}

.actions-cell {
  display: flex;
  gap: var(--spacing-sm);
  align-items: center;
}

.btn-action {
  padding: var(--spacing-sm) var(--spacing-md);
  border: none;
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.btn-edit {
  background: linear-gradient(135deg, var(--color-primary), #1e3a8a);
  color: var(--color-white);
}

.btn-edit:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 12px -2px rgba(30, 64, 175, 0.3);
}

.btn-delete {
  background: rgba(239, 68, 68, 0.1);
  color: var(--color-danger);
  border: 1px solid rgba(239, 68, 68, 0.3);
}

.btn-delete:hover {
  background: rgba(239, 68, 68, 0.2);
  border-color: var(--color-danger);
}

.btn-view {
  background: rgba(30, 64, 175, 0.1);
  color: var(--color-primary);
  border: 1px solid rgba(30, 64, 175, 0.3);
}

.btn-view:hover {
  background: rgba(30, 64, 175, 0.2);
  border-color: var(--color-primary);
}

.pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  background: var(--color-light);
  border-top: 1px solid var(--color-border);
}

.pagination-btn {
  padding: var(--spacing-sm) var(--spacing-md);
  border: 1px solid var(--color-border);
  background: var(--color-white);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: var(--transition);
  font-weight: 600;
  min-width: 40px;
}

.pagination-btn:hover:not(:disabled) {
  border-color: var(--color-primary);
  color: var(--color-primary);
  background: rgba(30, 64, 175, 0.05);
}

.pagination-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pagination-btn.active {
  background: linear-gradient(135deg, var(--color-primary), #1e3a8a);
  color: var(--color-white);
  border-color: var(--color-primary);
}

.empty-state {
  text-align: center;
  padding: var(--spacing-2xl);
  color: var(--color-text-light);
}

.empty-state-icon {
  font-size: 3rem;
  margin-bottom: var(--spacing-lg);
  opacity: 0.5;
}

.empty-state-text {
  font-size: 1.1rem;
  margin-bottom: var(--spacing-md);
}

.loading-spinner {
  display: inline-block;
  width: 40px;
  height: 40px;
  border: 4px solid rgba(30, 64, 175, 0.1);
  border-top-color: var(--color-primary);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ==========================================
   RESPONSIVE DESIGN
   ========================================== */

@media (max-width: 991px) {
  .productos-container {
    padding: var(--spacing-lg);
  }

  .productos-header {
    flex-direction: column;
    align-items: flex-start;
  }

  .filter-grid {
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  }

  .productos-th,
  .productos-td {
    padding: var(--spacing-md);
    font-size: 0.9rem;
  }

  .btn-action {
    padding: var(--spacing-xs) var(--spacing-sm);
    font-size: 0.75rem;
  }
}

@media (max-width: 767px) {
  .productos-container {
    padding: var(--spacing-md);
  }

  .productos-title {
    font-size: 1.5rem;
  }

  .filter-grid {
    grid-template-columns: 1fr;
  }

  .filter-buttons {
    flex-direction: column;
  }

  .btn-filter {
    width: 100%;
  }

  .productos-table-container {
    overflow-x: auto;
  }

  .productos-table {
    min-width: 600px;
  }

  .btn-action {
    padding: var(--spacing-xs) var(--spacing-sm);
    gap: 0;
  }

  .actions-cell {
    flex-wrap: wrap;
  }

  .pagination {
    flex-wrap: wrap;
  }

  .btn-crear-producto {
    width: 100%;
    justify-content: center;
  }
}

agregarProducto:
/* ==========================================
   AGREGARPRODUCTO.CSS - Add Product Form
   ========================================== */

:root {
  --color-primary: #1e40af;
  --color-secondary: #0f172a;
  --color-success: #10b981;
  --color-warning: #f59e0b;
  --color-danger: #ef4444;
  --color-light: #f3f4f6;
  --color-border: #e5e7eb;
  --color-text: #1f2937;
  --color-text-light: #6b7280;
  --color-white: #ffffff;
  --spacing-xs: 0.25rem;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 1.5rem;
  --spacing-xl: 2rem;
  --spacing-2xl: 3rem;
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
  --transition: all 0.3s ease;
}

.agregar-producto-container {
  width: 100%;
  min-height: 100vh;
  background: linear-gradient(135deg, #f3f4f6 0%, #ffffff 100%);
  padding: var(--spacing-xl);
  display: flex;
  align-items: center;
  justify-content: center;
}

.agregar-producto-wrapper {
  width: 100%;
  max-width: 700px;
}

.form-header {
  margin-bottom: var(--spacing-2xl);
  text-align: center;
}

.form-title {
  font-size: 2rem;
  font-weight: 700;
  color: var(--color-secondary);
  margin: 0 0 var(--spacing-md) 0;
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.form-subtitle {
  font-size: 0.95rem;
  color: var(--color-text-light);
  margin: 0;
}

.agregar-producto-form {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  padding: var(--spacing-2xl);
  box-shadow: var(--shadow-lg);
  border: 1px solid var(--color-border);
}

.form-section {
  margin-bottom: var(--spacing-xl);
}

.section-title {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-secondary);
  margin: 0 0 var(--spacing-lg) 0;
  padding-bottom: var(--spacing-md);
  border-bottom: 2px solid var(--color-light);
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.section-icon {
  font-size: 1.3rem;
  color: var(--color-primary);
}

.form-group {
  margin-bottom: var(--spacing-lg);
}

.form-label {
  display: block;
  font-weight: 600;
  color: var(--color-text);
  margin-bottom: var(--spacing-sm);
  font-size: 0.95rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.label-required {
  color: var(--color-danger);
  font-size: 1.1em;
  margin-left: var(--spacing-xs);
}

.form-input,
.form-select,
.form-textarea {
  width: 100%;
  padding: var(--spacing-md);
  border: 2px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 0.95rem;
  font-family: inherit;
  color: var(--color-text);
  background: var(--color-white);
  transition: var(--transition);
  box-sizing: border-box;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 4px rgba(30, 64, 175, 0.1);
  background: linear-gradient(to bottom, var(--color-white), #fafbfc);
}

.form-input::placeholder {
  color: var(--color-text-light);
}

.form-input.error,
.form-select.error,
.form-textarea.error {
  border-color: var(--color-danger);
  background: rgba(239, 68, 68, 0.02);
}

.form-input.error:focus,
.form-select.error:focus,
.form-textarea.error:focus {
  box-shadow: 0 0 0 4px rgba(239, 68, 68, 0.1);
}

.form-textarea {
  resize: vertical;
  min-height: 120px;
  font-family: inherit;
}

.form-help-text {
  font-size: 0.85rem;
  color: var(--color-text-light);
  margin-top: var(--spacing-xs);
  display: block;
}

.form-error-text {
  font-size: 0.85rem;
  color: var(--color-danger);
  margin-top: var(--spacing-xs);
  display: block;
  font-weight: 600;
}

.form-row {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: var(--spacing-lg);
}

.form-group-full {
  grid-column: 1 / -1;
}

.input-group {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.input-icon {
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--color-light);
  border-radius: var(--radius-md);
  color: var(--color-primary);
  font-weight: 700;
}

.input-with-icon {
  position: relative;
  display: flex;
  align-items: center;
}

.input-with-icon .form-input {
  padding-left: 40px;
}

.input-icon-left {
  position: absolute;
  left: var(--spacing-md);
  color: var(--color-primary);
  font-size: 1.1rem;
  pointer-events: none;
}

.form-checkbox-group,
.form-radio-group {
  display: flex;
  gap: var(--spacing-lg);
  flex-wrap: wrap;
}

.form-checkbox,
.form-radio {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  cursor: pointer;
}

.form-checkbox input,
.form-radio input {
  cursor: pointer;
  width: 18px;
  height: 18px;
  accent-color: var(--color-primary);
}

.form-checkbox label,
.form-radio label {
  cursor: pointer;
  font-weight: 500;
  color: var(--color-text);
}

.form-actions {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-lg);
  margin-top: var(--spacing-2xl);
  padding-top: var(--spacing-xl);
  border-top: 1px solid var(--color-border);
}

.btn-submit,
.btn-cancel {
  padding: var(--spacing-md) var(--spacing-lg);
  border: none;
  border-radius: var(--radius-md);
  font-size: 1rem;
  font-weight: 700;
  cursor: pointer;
  transition: var(--transition);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-sm);
  min-height: 48px;
}

.btn-submit {
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  color: var(--color-white);
  box-shadow: var(--shadow-md);
}

.btn-submit:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 12px 24px -6px rgba(30, 64, 175, 0.4);
}

.btn-submit:active {
  transform: translateY(0);
}

.btn-submit:disabled {
  opacity: 0.6;
  cursor: not-allowed;
  box-shadow: var(--shadow-sm);
}

.btn-cancel {
  background: var(--color-light);
  color: var(--color-text);
  border: 2px solid var(--color-border);
}

.btn-cancel:hover {
  background: #e5e7eb;
  border-color: #d1d5db;
}

.btn-cancel:active {
  background: #d1d5db;
}

.success-message {
  background: rgba(16, 185, 129, 0.1);
  border-left: 4px solid var(--color-success);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  margin-bottom: var(--spacing-lg);
  color: var(--color-success);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.error-message {
  background: rgba(239, 68, 68, 0.1);
  border-left: 4px solid var(--color-danger);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  margin-bottom: var(--spacing-lg);
  color: var(--color-danger);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.warning-message {
  background: rgba(245, 158, 11, 0.1);
  border-left: 4px solid var(--color-warning);
  border-radius: var(--radius-md);
  padding: var(--spacing-lg);
  margin-bottom: var(--spacing-lg);
  color: var(--color-warning);
  font-weight: 600;
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.loading-spinner-btn {
  display: inline-block;
  width: 20px;
  height: 20px;
  border: 3px solid rgba(255, 255, 255, 0.3);
  border-top-color: var(--color-white);
  border-radius: 50%;
  animation: spin-btn 0.8s linear infinite;
}

@keyframes spin-btn {
  to { transform: rotate(360deg); }
}

.form-progress {
  display: flex;
  gap: var(--spacing-sm);
  margin-bottom: var(--spacing-xl);
}

.progress-step {
  flex: 1;
  height: 4px;
  background: var(--color-light);
  border-radius: var(--radius-sm);
  overflow: hidden;
}

.progress-step.active {
  background: linear-gradient(90deg, var(--color-primary) 0%, #1e3a8a 100%);
}

.progress-step.completed {
  background: var(--color-success);
}

/* ==========================================
   RESPONSIVE DESIGN
   ========================================== */

@media (max-width: 991px) {
  .agregar-producto-form {
    padding: var(--spacing-xl);
  }

  .form-row {
    grid-template-columns: 1fr;
  }

  .btn-submit,
  .btn-cancel {
    padding: var(--spacing-md) var(--spacing-lg);
  }
}

@media (max-width: 767px) {
  .agregar-producto-container {
    padding: var(--spacing-md);
  }

  .agregar-producto-wrapper {
    max-width: 100%;
  }

  .form-title {
    font-size: 1.5rem;
  }

  .agregar-producto-form {
    padding: var(--spacing-lg);
    border-radius: var(--radius-md);
  }

  .form-actions {
    grid-template-columns: 1fr;
    gap: var(--spacing-md);
  }

  .btn-submit,
  .btn-cancel {
    width: 100%;
    padding: var(--spacing-md);
  }

  .section-title {
    font-size: 1rem;
  }

  .form-label {
    font-size: 0.9rem;
  }

  .form-input,
  .form-select,
  .form-textarea {
    font-size: 16px;
  }

  .form-group {
    margin-bottom: var(--spacing-md);
  }

  .form-section {
    margin-bottom: var(--spacing-lg);
  }
}

stokcProducto:
/* ==========================================
   STOCVPRODUCTO.CSS - Stock Inventory
   ========================================== */

:root {
  --color-primary: #1e40af;
  --color-secondary: #0f172a;
  --color-success: #10b981;
  --color-warning: #f59e0b;
  --color-danger: #ef4444;
  --color-info: #3b82f6;
  --color-light: #f3f4f6;
  --color-border: #e5e7eb;
  --color-text: #1f2937;
  --color-text-light: #6b7280;
  --color-white: #ffffff;
  --spacing-xs: 0.25rem;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 1.5rem;
  --spacing-xl: 2rem;
  --spacing-2xl: 3rem;
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 12px;
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);
  --transition: all 0.3s ease;
}

.stock-producto-container {
  width: 100%;
  padding: var(--spacing-xl);
  background: linear-gradient(135deg, #f3f4f6 0%, #ffffff 100%);
  min-height: 100vh;
}

.stock-header {
  margin-bottom: var(--spacing-2xl);
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--spacing-lg);
}

.stock-title {
  font-size: 2rem;
  font-weight: 700;
  color: var(--color-secondary);
  background: linear-gradient(135deg, var(--color-primary) 0%, #1e3a8a 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin: 0;
}

.stock-controls {
  display: flex;
  gap: var(--spacing-md);
  align-items: center;
  flex-wrap: wrap;
}

.stock-search-box {
  position: relative;
  display: flex;
  align-items: center;
  background: var(--color-white);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--spacing-sm);
  box-shadow: var(--shadow-sm);
}

.stock-search-input {
  border: none;
  background: transparent;
  padding: var(--spacing-sm) var(--spacing-md);
  font-size: 0.95rem;
  width: 250px;
  color: var(--color-text);
}

.stock-search-input::placeholder {
  color: var(--color-text-light);
}

.stock-search-input:focus {
  outline: none;
}

.search-icon {
  color: var(--color-primary);
  margin-right: var(--spacing-md);
}

.stock-export-btn {
  background: linear-gradient(135deg, var(--color-success), #059669);
  color: var(--color-white);
  border: none;
  padding: var(--spacing-md) var(--spacing-lg);
  border-radius: var(--radius-md);
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  box-shadow: var(--shadow-md);
}

.stock-export-btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 20px -4px rgba(16, 185, 129, 0.3);
}

.stock-stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: var(--spacing-lg);
  margin-bottom: var(--spacing-2xl);
}

.stat-card {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  border: 1px solid var(--color-border);
  box-shadow: var(--shadow-md);
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: var(--spacing-lg);
  transition: var(--transition);
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
}

.stat-content {
  flex: 1;
}

.stat-label {
  font-size: 0.85rem;
  color: var(--color-text-light);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-weight: 600;
  margin-bottom: var(--spacing-sm);
}

.stat-value {
  font-size: 1.8rem;
  font-weight: 700;
  color: var(--color-secondary);
}

.stat-change {
  font-size: 0.85rem;
  font-weight: 600;
  margin-top: var(--spacing-xs);
}

.stat-change.positive {
  color: var(--color-success);
}

.stat-change.negative {
  color: var(--color-danger);
}

.stat-icon {
  width: 60px;
  height: 60px;
  border-radius: var(--radius-md);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.8rem;
  flex-shrink: 0;
}

.stat-icon.primary {
  background: linear-gradient(135deg, rgba(30, 64, 175, 0.1), rgba(30, 64, 175, 0.05));
  color: var(--color-primary);
}

.stat-icon.success {
  background: linear-gradient(135deg, rgba(16, 185, 129, 0.1), rgba(16, 185, 129, 0.05));
  color: var(--color-success);
}

.stat-icon.warning {
  background: linear-gradient(135deg, rgba(245, 158, 11, 0.1), rgba(245, 158, 11, 0.05));
  color: var(--color-warning);
}

.stat-icon.danger {
  background: linear-gradient(135deg, rgba(239, 68, 68, 0.1), rgba(239, 68, 68, 0.05));
  color: var(--color-danger);
}

.stock-filters {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  margin-bottom: var(--spacing-xl);
  border: 1px solid var(--color-border);
  box-shadow: var(--shadow-sm);
}

.filter-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: var(--spacing-lg);
}

.filter-group {
  display: flex;
  flex-direction: column;
}

.filter-label {
  font-size: 0.875rem;
  font-weight: 600;
  color: var(--color-text);
  margin-bottom: var(--spacing-sm);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.filter-select {
  padding: var(--spacing-md);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  font-size: 0.95rem;
  background: var(--color-white);
  color: var(--color-text);
  cursor: pointer;
  transition: var(--transition);
  font-family: inherit;
}

.filter-select:focus {
  outline: none;
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px rgba(30, 64, 175, 0.1);
}

.stock-table-container {
  background: var(--color-white);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-md);
  border: 1px solid var(--color-border);
}

.stock-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.95rem;
}

.stock-thead {
  background: linear-gradient(to right, #f9fafb, #f3f4f6);
  border-bottom: 2px solid var(--color-border);
}

.stock-th {
  padding: var(--spacing-lg);
  text-align: left;
  font-weight: 700;
  color: var(--color-secondary);
  text-transform: uppercase;
  font-size: 0.875rem;
  letter-spacing: 0.5px;
  white-space: nowrap;
  user-select: none;
  cursor: pointer;
  transition: var(--transition);
}

.stock-th:hover {
  background: #f0f1f3;
}

.stock-th.sortable::after {
  content: '⇅';
  margin-left: var(--spacing-sm);
  opacity: 0.5;
  font-size: 0.8rem;
}

.stock-th.sorted::after {
  opacity: 1;
}

.stock-tbody tr {
  border-bottom: 1px solid var(--color-border);
  transition: var(--transition);
}

.stock-tbody tr:hover {
  background: linear-gradient(to right, #f9fafb, #f3f4f6);
}

.stock-td {
  padding: var(--spacing-lg);
  color: var(--color-text);
  vertical-align: middle;
}

.product-info {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.product-thumbnail {
  width: 40px;
  height: 40px;
  border-radius: var(--radius-md);
  background: linear-gradient(135deg, rgba(30, 64, 175, 0.1), rgba(30, 64, 175, 0.05));
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--color-primary);
  font-weight: 700;
  font-size: 0.9rem;
}

.product-details {
  flex: 1;
}

.product-name {
  font-weight: 600;
  color: var(--color-primary);
  margin: 0;
  display: block;
}

.product-sku {
  font-size: 0.85rem;
  color: var(--color-text-light);
  font-family: 'Courier New', monospace;
  margin: 0;
  display: block;
}

.stock-level {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.stock-bar {
  width: 100px;
  height: 8px;
  background: var(--color-light);
  border-radius: var(--radius-sm);
  overflow: hidden;
  position: relative;
}

.stock-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--color-primary), #1e3a8a);
  border-radius: var(--radius-sm);
  transition: width 0.3s ease;
}

.stock-bar.low .stock-bar-fill {
  background: linear-gradient(90deg, var(--color-danger), #dc2626);
}

.stock-bar.medium .stock-bar-fill {
  background: linear-gradient(90deg, var(--color-warning), #d97706);
}

.stock-bar.high .stock-bar-fill {
  background: linear-gradient(90deg, var(--color-success), #059669);
}

.stock-value {
  font-weight: 600;
  color: var(--color-secondary);
  min-width: 50px;
  text-align: right;
}

.stock-status-badge {
  display: inline-block;
  padding: var(--spacing-xs) var(--spacing-md);
  border-radius: var(--radius-sm);
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  width: fit-content;
  border-left: 3px solid;
}

.status-in-stock {
  background: rgba(16, 185, 129, 0.1);
  color: var(--color-success);
  border-left-color: var(--color-success);
}

.status-low-stock {
  background: rgba(245, 158, 11, 0.1);
  color: var(--color-warning);
  border-left-color: var(--color-warning);
}

.status-critical {
  background: rgba(239, 68, 68, 0.1);
  color: var(--color-danger);
  border-left-color: var(--color-danger);
}

.status-discontinued {
  background: rgba(107, 114, 128, 0.1);
  color: var(--color-text-light);
  border-left-color: var(--color-text-light);
}

.unit-price {
  font-weight: 600;
  color: var(--color-success);
  font-size: 1.05rem;
}

.total-value {
  font-weight: 700;
  color: var(--color-primary);
  font-size: 1.1rem;
}

.last-updated {
  font-size: 0.85rem;
  color: var(--color-text-light);
}

.actions-cell {
  display: flex;
  gap: var(--spacing-sm);
  align-items: center;
}

.btn-action {
  padding: var(--spacing-sm) var(--spacing-md);
  border: none;
  border-radius: var(--radius-sm);
  font-size: 0.85rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-xs);
}

.btn-restock {
  background: linear-gradient(135deg, var(--color-info), #2563eb);
  color: var(--color-white);
}

.btn-restock:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 12px -2px rgba(59, 130, 246, 0.3);
}

.btn-adjust {
  background: rgba(30, 64, 175, 0.1);
  color: var(--color-primary);
  border: 1px solid rgba(30, 64, 175, 0.3);
}

.btn-adjust:hover {
  background: rgba(30, 64, 175, 0.2);
  border-color: var(--color-primary);
}

.btn-view {
  background: rgba(107, 114, 128, 0.1);
  color: var(--color-text-light);
  border: 1px solid rgba(107, 114, 128, 0.3);
}

.btn-view:hover {
  background: rgba(107, 114, 128, 0.2);
  border-color: var(--color-text-light);
}

.pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-xl);
  background: var(--color-light);
  border-top: 1px solid var(--color-border);
}

.pagination-btn {
  padding: var(--spacing-sm) var(--spacing-md);
  border: 1px solid var(--color-border);
  background: var(--color-white);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: var(--transition);
  font-weight: 600;
  min-width: 40px;
}

.pagination-btn:hover:not(:disabled) {
  border-color: var(--color-primary);
  color: var(--color-primary);
  background: rgba(30, 64, 175, 0.05);
}

.pagination-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pagination-btn.active {
  background: linear-gradient(135deg, var(--color-primary), #1e3a8a);
  color: var(--color-white);
  border-color: var(--color-primary);
}

.empty-state {
  text-align: center;
  padding: var(--spacing-2xl);
  color: var(--color-text-light);
}

.empty-state-icon {
  font-size: 3rem;
  margin-bottom: var(--spacing-lg);
  opacity: 0.5;
}

.empty-state-text {
  font-size: 1.1rem;
  margin-bottom: var(--spacing-md);
}

/* ==========================================
   RESPONSIVE DESIGN
   ========================================== */

@media (max-width: 991px) {
  .stock-container {
    padding: var(--spacing-lg);
  }

  .stock-header {
    flex-direction: column;
    align-items: flex-start;
  }

  .stock-controls {
    width: 100%;
    flex-direction: column;
  }

  .stock-search-input {
    width: 100%;
  }

  .stock-export-btn {
    width: 100%;
    justify-content: center;
  }

  .stock-stats {
    grid-template-columns: repeat(2, 1fr);
  }

  .filter-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .stock-th,
  .stock-td {
    padding: var(--spacing-md);
    font-size: 0.9rem;
  }

  .product-info {
    flex-direction: column;
    align-items: flex-start;
  }

  .btn-action {
    padding: var(--spacing-xs) var(--spacing-sm);
    font-size: 0.75rem;
  }
}

@media (max-width: 767px) {
  .stock-producto-container {
    padding: var(--spacing-md);
  }

  .stock-title {
    font-size: 1.5rem;
  }

  .stock-controls {
    width: 100%;
    flex-direction: column;
  }

  .stock-search-box {
    width: 100%;
  }

  .stock-search-input {
    width: 100%;
  }

  .stock-export-btn {
    width: 100%;
  }

  .stock-stats {
    grid-template-columns: 1fr;
  }

  .stat-card {
    padding: var(--spacing-lg);
  }

  .filter-grid {
    grid-template-columns: 1fr;
  }

  .stock-table-container {
    overflow-x: auto;
  }

  .stock-table {
    min-width: 700px;
  }

  .stock-th,
  .stock-td {
    padding: var(--spacing-md);
  }

  .product-thumbnail {
    width: 35px;
    height: 35px;
  }

  .product-name {
    font-size: 0.95rem;
  }

  .product-sku {
    font-size: 0.75rem;
  }

  .stock-bar {
    width: 60px;
  }

  .actions-cell {
    flex-direction: column;
    align-items: flex-start;
  }

  .btn-action {
    width: 100%;
    justify-content: center;
  }

  .pagination {
    flex-wrap: wrap;
  }
}
